import React from 'react';
import { Button, ButtonProps } from 'antd';
import cn from 'classnames';
import './medallion-button.css';

export const ButtonVariant = {
    Primary: 'primary',
    Secondary: 'secondary',
    Tertiary: 'tertiary',
    Destructive: 'destructive',
} as const;

export type ButtonVariant = 'primary' | 'secondary' | 'tertiary' | 'destructive';

export const ButtonSize = {
    Small: 'small',
    Medium: 'medium',
    Large: 'large',
} as const;

export type ButtonSize = 'small' | 'medium' | 'large';

export interface MedallionButtonProps extends Omit<ButtonProps, 'type' | 'size'> {
    /** Text content */
    label?: string;
    /** Button visual variant */
    variant?: ButtonVariant;
    /** Button size */
    size?: ButtonSize;
    /** Active state (for secondary/tertiary variants only) */
    active?: boolean;
    /** Leading icon component */
    leadingIcon?: React.ReactNode;
    /** Trailing icon component */
    trailingIcon?: React.ReactNode;
    /** Icon-only button — requires aria-label, no label prop */
    icon?: React.ReactNode;
}

export const MedallionButton: React.FC<MedallionButtonProps> = ({
    label,
    variant = ButtonVariant.Secondary,
    size = ButtonSize.Medium,
    active = false,
    leadingIcon,
    trailingIcon,
    icon,
    loading = false,
    disabled = false,
    className,
    ...rest
}) => {
    const normalizedSize =
        size === ButtonSize.Small ? 'sm' : size === ButtonSize.Medium ? 'md' : 'lg';
    const isIconOnly = !!icon && !label;

    const buttonClassName = cn(
        'mds-button',
        `mds-variant-${variant}`,
        `mds-size-${normalizedSize}`,
        {
            'mds-icon-only': isIconOnly,
            'mds-button--active': active,
        },
        className
    );

    return (
        <Button
            className={buttonClassName}
            loading={loading}
            disabled={disabled}
            {...rest}
        >
            {leadingIcon && (
                <span className="mds-icon mds-icon-left">{leadingIcon}</span>
            )}
            {label}
            {trailingIcon && (
                <span className="mds-icon mds-icon-right">{trailingIcon}</span>
            )}
            {icon && !label && (
                <span className="mds-icon mds-icon-only-icon">{icon}</span>
            )}
        </Button>
    );
};

export default MedallionButton;

/* MDS Button — resolved design tokens */

.mds-button {
    border-radius: 6px !important;
    font-weight: 500 !important;
    transition: all 200ms cubic-bezier(0.4, 0, 0.2, 1);
    align-items: center;
    justify-content: center;
    position: relative;
    cursor: pointer;
}

.mds-button .mds-icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
}

.mds-button.mds-size-sm { height: 24px; padding: 0 12px; font-size: 12px; gap: 4px; line-height: 1; }
.mds-button.mds-size-md { height: 32px; padding: 0 14px; font-size: 14px; gap: 6px; line-height: 1; }
.mds-button.mds-size-lg { height: 40px; padding: 0 16px; font-size: 16px; gap: 8px; line-height: 1; }

.mds-button.mds-size-sm .mds-icon-left, .mds-button.mds-size-sm .mds-icon-right, .mds-button.mds-size-sm .mds-icon-only-icon { width: 14px; height: 14px; font-size: 14px; }
.mds-button.mds-size-md .mds-icon-left, .mds-button.mds-size-md .mds-icon-right, .mds-button.mds-size-md .mds-icon-only-icon { width: 16px; height: 16px; font-size: 16px; }
.mds-button.mds-size-lg .mds-icon-left, .mds-button.mds-size-lg .mds-icon-right, .mds-button.mds-size-lg .mds-icon-only-icon { width: 20px; height: 20px; font-size: 20px; }

.mds-button.mds-icon-only.mds-size-sm { width: 24px; padding: 0; }
.mds-button.mds-icon-only.mds-size-md { width: 32px; padding: 0; }
.mds-button.mds-icon-only.mds-size-lg { width: 40px; padding: 0; }

.mds-button.mds-variant-primary { background-color: #3953ec; border-color: #3953ec; color: #ffffff; }
.mds-button.mds-variant-primary:hover:not(:disabled) { background-color: #647ffa; border-color: #647ffa; color: #ffffff; }
.mds-button.mds-variant-primary:active:not(:disabled) { background-color: #2639c7; border-color: #2639c7; color: #ffffff; }
.mds-button.mds-variant-primary:focus-visible { outline: 2px solid rgba(38,57,199,0.3); outline-offset: 2px; }
.mds-button.mds-variant-primary:disabled { cursor: not-allowed; background-color: #d4d4d8; border-color: #d4d4d8; color: #9f9fa9; }

.mds-button.mds-variant-secondary { background-color: #ffffff; border-color: #9f9fa9; color: #09090b; }
.mds-button.mds-variant-secondary:hover:not(:disabled):not(.mds-button--active) { background-color: #f4f4f5; border-color: #52525c; color: #09090b; }
.mds-button.mds-variant-secondary:active:not(:disabled):not(.mds-button--active) { background-color: #e4e4e7; border-color: #52525c; color: #09090b; }
.mds-button.mds-variant-secondary:focus-visible { outline: 2px solid rgba(82,82,92,0.3); outline-offset: 2px; }
.mds-button.mds-variant-secondary:disabled { cursor: not-allowed; background-color: #ffffff; border-color: #e4e4e7; color: #9f9fa9; }
.mds-button.mds-variant-secondary.mds-button--active { background-color: #eff6ff; border-color: #2b7fff; color: #155dfc; }

.mds-button.mds-variant-tertiary { background-color: transparent; border-color: transparent; color: #09090b; }
.mds-button.mds-variant-tertiary:hover:not(:disabled):not(.mds-button--active) { background-color: rgba(0,0,0,0.05); border-color: rgba(0,0,0,0.05); color: #09090b; }
.mds-button.mds-variant-tertiary:active:not(:disabled):not(.mds-button--active) { background-color: rgba(0,0,0,0.1); border-color: rgba(0,0,0,0.1); color: #09090b; }
.mds-button.mds-variant-tertiary:focus-visible { outline: 2px solid rgba(9,9,11,0.3); outline-offset: 2px; }
.mds-button.mds-variant-tertiary:disabled { cursor: not-allowed; background-color: transparent; color: #9f9fa9; }
.mds-button.mds-variant-tertiary.mds-button--active { background-color: #eff6ff; color: #155dfc; }

.mds-button.mds-variant-destructive { background-color: #c10007; color: #ffffff; }
.mds-button.mds-variant-destructive:hover:not(:disabled) { background-color: #9f0712; border: 1px solid #9f0712; color: #ffffff; }
.mds-button.mds-variant-destructive:active:not(:disabled) { background-color: #82181a; border-color: #82181a; color: #ffffff; }
.mds-button.mds-variant-destructive:focus-visible { outline: 2px solid rgba(193,0,7,0.3) !important; outline-offset: 2px !important; }
.mds-button.mds-variant-destructive:disabled { cursor: not-allowed; background-color: #d4d4d8; color: #9f9fa9; }

.mds-button.ant-btn-loading { cursor: progress; transform: none; box-shadow: none; }
.mds-button.ant-btn-loading .mds-icon-left, .mds-button.ant-btn-loading .mds-icon-right, .mds-button.ant-btn-loading .mds-icon-only-icon { display: none; }

.mds-button .mds-icon-left { margin-right: 0; }
.mds-button .mds-icon-right { margin-left: 0; }
.mds-button .mds-icon-only-icon { margin: 0; }
